interface Accessor<T> {
    get(): T;
    set(value: T): void;
}
interface AccessorGet<T> {
    get(): T;
}
interface AccessorSet<T> {
    set(value: T): void;
}
type Accessible<T> = Partial<Accessor<T>>;

interface Observable<T> {
    subscribe(listener: (value: T) => void): Subscription;
}

type Subscription = {
    unsubscribe: () => void;
};

interface Guarded<T extends Original, Original = unknown> {
    valid(value: Original): value is T;
}

export type { AccessorGet as A, Guarded as G, Observable as O, Subscription as S, AccessorSet as a, Accessible as b };
